import{_ as t,o,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const s="/orrery/docs/assets/locale-ja.Df8EhQhQ.png",n="/orrery/docs/assets/01-explore.B_39jrpc.png",i="/orrery/docs/assets/11-science-lens-explore.abeeDxHu.png",l="/orrery/docs/assets/02-plan.DYzOf_sm.png",c="/orrery/docs/assets/13-mission-sandbox.DH9KXX1O.png",d="/orrery/docs/assets/03-fly-curiosity.D2KcWR_k.png",g="/orrery/docs/assets/03-fly-apollo11.C5suqKYz.png",h="/orrery/docs/assets/12-flight-director.CkD19fZc.png",p="/orrery/docs/assets/04-missions.C7Y0XAnj.png",u="/orrery/docs/assets/mission-panel.Uiq4Bfki.png",m="/orrery/docs/assets/05-earth.DQfeY6kb.png",y="/orrery/docs/assets/06-moon.BMxnClzE.png",f="/orrery/docs/assets/07-mars.BzrZYuLv.png",b="/orrery/docs/assets/08-iss.MB4zGZO2.png",v="/orrery/docs/assets/09-tiangong.Dn-D_wbq.png",w="/orrery/docs/assets/10-science-landing.4SKM85Ud.png",k="/orrery/docs/assets/10-science-section.83LjbDPf.png",S="/orrery/docs/assets/14-credits.BGSoGwMD.png",E="/orrery/docs/assets/15-library.KHGyn62T.png",P=JSON.parse('{"title":"User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide.md","filePath":"user-guide.md"}'),x={name:"user-guide.md"};function A(C,e,L,D,R,M){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="user-guide" tabindex="-1">User Guide <a class="header-anchor" href="#user-guide" aria-label="Permalink to &quot;User Guide&quot;">​</a></h1><p><em>Orrery — read-this-first guide for the live app · v0.5.x · May 2026</em></p><blockquote><p>Every screenshot in this guide comes from the production app at 1280×800. Click any image to open it full-size in a new tab.</p></blockquote><hr><h2 id="switching-language" tabindex="-1">Switching language <a class="header-anchor" href="#switching-language" aria-label="Permalink to &quot;Switching language&quot;">​</a></h2><p>A locale picker sits in the top-right of the navigation bar. The chip shows your country flag + the locale&#39;s short tag (e.g. 🇩🇪 DE). Click it to open the dropdown, pick your language, and the URL updates to <code>?lang=&lt;code&gt;</code>. Bookmark the URL to lock your locale; share it and your reader gets the same.</p><p>There is no <code>localStorage</code> and no cookie — the URL is the only place your locale lives. On a fresh visit the browser language is sniffed (<code>navigator.language</code>) and applied automatically; if it doesn&#39;t match a supported locale, English is the default.</p><p><a href="screenshots/locale-ja.png"><img src="'+s+'" alt="Japanese locale"></a></p><p><strong>Currently shipped — 14 languages, all at 100% UI parity:</strong></p><table tabindex="0"><thead><tr><th>Locale</th><th>Native name</th><th>Notes</th></tr></thead><tbody><tr><td><code>en-US</code></td><td>English</td><td>Source language</td></tr><tr><td><code>es</code></td><td>Español</td><td>First non-English locale (v0.3.0)</td></tr><tr><td><code>fr</code></td><td>Français</td><td></td></tr><tr><td><code>de</code></td><td>Deutsch</td><td></td></tr><tr><td><code>pt-BR</code></td><td>Português (BR)</td><td></td></tr><tr><td><code>it</code></td><td>Italiano</td><td></td></tr><tr><td><code>nl</code></td><td>Nederlands</td><td>Added v0.5.x (issue #72)</td></tr><tr><td><code>zh-CN</code></td><td>中文 (简体)</td><td></td></tr><tr><td><code>ja</code></td><td>日本語</td><td></td></tr><tr><td><code>ko</code></td><td>한국어</td><td></td></tr><tr><td><code>hi</code></td><td>हिन्दी</td><td>Devanagari</td></tr><tr><td><code>ar</code></td><td>العربية</td><td>RTL — flips the entire layout</td></tr><tr><td><code>ru</code></td><td>Русский</td><td>Cyrillic</td></tr><tr><td><code>sr-Cyrl</code></td><td>Српски</td><td>Serbian Cyrillic</td></tr></tbody></table><p>The <code>/science</code> encyclopedia overlay tree is translated end-to-end across <strong>all 14 locales</strong>. Editorial entity overlays (missions, planets, sites, modules) are translated across all 14 locales for the v0.5.x rollout.</p><hr><h2 id="solar-system-explorer-·-explore" tabindex="-1">Solar System Explorer · <code>/explore</code> <a class="header-anchor" href="#solar-system-explorer-·-explore" aria-label="Permalink to &quot;Solar System Explorer · `/explore`&quot;">​</a></h2><p>A real-time 3D / 2D orrery showing 8 planets, 5 dwarf planets, 2 comets, and ʻOumuamua (the only confirmed interstellar object).</p><p><a href="screenshots/01-explore.png"><img src="'+n+'" alt="Explorer screenshot"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Drag</strong> the 3D scene to orbit around the Sun.</li><li><strong>Scroll</strong> / <strong>pinch</strong> to zoom.</li><li><strong>Click any body</strong> — Sun, planet, dwarf, comet, ʻOumuamua — to open its detail panel with <strong>OVERVIEW · GALLERY · TECHNICAL · SCIENCE</strong> tabs.</li><li><strong>Hover</strong> in 3D for a velocity tooltip (mean orbital velocity via vis-viva).</li><li><strong><code>2D</code> toggle</strong> (top right) — switches to a top-down 2D plot of the ecliptic plane.</li><li><strong><code>REFERENCES</code> toggle</strong> — opens a true-relative-size diorama of the planets.</li><li><strong><code>LAYERS</code> toggle</strong> — show / hide PLANETS · DWARFS · COMETS · INTERSTELLAR independently. Hidden bodies aren&#39;t clickable.</li></ul><p><strong>Turn on the Science Lens</strong> (the lens icon in the nav) and the scene becomes a textbook layer:</p><p><a href="screenshots/11-science-lens-explore.png"><img src="'+i+'" alt="Science Lens on /explore"></a></p><p>A <strong>Science Lens banner</strong> above the canvas explains the current view in plain language; a <strong>Science Layers panel</strong> lets you toggle individual physics layers (gravity vectors, velocity vectors, centripetal arrows, apsides + true anomaly, sphere-of-influence rings, hover info cards). Layer values print at arrow tips so you can compare magnitudes across planets.</p><hr><h2 id="mission-configurator-·-plan" tabindex="-1">Mission Configurator · <code>/plan</code> <a class="header-anchor" href="#mission-configurator-·-plan" aria-label="Permalink to &quot;Mission Configurator · `/plan`&quot;">​</a></h2><p>The Lambert porkchop plot. Pick a destination + mission type (LANDING or FLYBY). Each destination uses a <strong>pre-computed</strong> 112×100 grid (11,200 cells) checked in at <code>static/data/porkchop/</code> and loaded by the app at runtime — the Lambert <strong>Web Worker</strong> stays in the bundle for future custom-range work but is <strong>not</strong> what paints the default Mercury–Pluto maps. Cool teal cells are cheap launch windows; red cells are expensive.</p><p><a href="screenshots/02-plan.png"><img src="'+l+'" alt="Porkchop screenshot"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Click any cell</strong> to read the exact dep / arr dates, transit, and ∆v.</li><li><strong>Pick a vehicle</strong> from 13 launch rockets — the panel computes vehicle ∆v vs required ∆v and shows margin or deficit.</li><li><strong>▶ FLY MISSION</strong> — opens <code>/fly</code> with your selected dep / arr / vehicle baked into the URL.</li><li><strong>Mobile</strong>: long-press the porkchop for a magnifier loupe.</li></ul><p><strong>Mission Sandbox</strong> (lens on or off — always available): pin one cell with <code>📌 PIN THIS CELL</code>, then click another cell. The compare panel shows ΔDEP, ΔTOF, and Δ∆v (green chip when the new cell is cheaper, gold when more expensive). Pin clears automatically when you change destination.</p><p><a href="screenshots/13-mission-sandbox.png"><img src="'+c+'" alt="Mission Sandbox compare panel"></a></p><hr><h2 id="mission-arc-·-fly" tabindex="-1">Mission Arc · <code>/fly</code> <a class="header-anchor" href="#mission-arc-·-fly" aria-label="Permalink to &quot;Mission Arc · `/fly`&quot;">​</a></h2><p>The mission visualisation. Earth, the destination, and the spacecraft animate live; the trajectory tube uses a true two-point Keplerian ellipse with Sun at focus, so both endpoints lock to live planet positions.</p><p><a href="screenshots/03-fly-curiosity.png"><img src="'+d+'" alt="Curiosity flight"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Scrub the timeline</strong> — bottom bar — to fly the mission from launch to arrival.</li><li><strong>▶ / ⏸ + speed pills</strong> — autoplay at 1× / 7× / 30× / 90× (Mars-class missions) or 0.1× / 0.5× / 1× / 3× (lunar).</li><li><strong><code>2D</code> toggle</strong> — switch between the 3D scene and a top-down 2D view.</li><li><strong>CAPCOM panel</strong> (right) — live mission events (TLI, TCM, EDL, etc.) tick by as you scrub.</li><li><strong>Pre-built missions</strong>: try <code>/fly?mission=&lt;id&gt;</code> for any of the 36 missions in the catalog.</li><li><strong>Lunar missions</strong> (Apollo, Artemis II, Blue Moon, Chang&#39;e, Chandrayaan, Luna, SLIM) render heliocentrically with the Earth + Moon system orbiting the Sun, and the Moon orbiting Earth at an exaggerated visual distance so the cislunar trajectory is visible.</li></ul><p><a href="screenshots/03-fly-apollo11.png"><img src="'+g+'" alt="Apollo 11 fly"></a></p><p><strong>Turn on the Science Lens</strong> for the <strong>Flight Director banner</strong> — a 5-phase narration that flips through the mission as you scrub:</p><p><a href="screenshots/12-flight-director.png"><img src="'+h+'" alt="Flight Director on /fly"></a></p><table tabindex="0"><thead><tr><th>Phase</th><th>What it explains</th></tr></thead><tbody><tr><td><strong>DEPARTURE</strong></td><td>C3 launch energy, leaving Earth&#39;s gravity well</td></tr><tr><td><strong>TRANS-X INJECTION</strong></td><td>The biggest single ∆v of the trip — TLI for Moon, TMI for Mars</td></tr><tr><td><strong>CRUISE</strong></td><td>The Hohmann transfer ellipse, vis-viva at every point</td></tr><tr><td><strong>APPROACH</strong></td><td>V∞ excess speed, minimum braking ∆v before insertion</td></tr><tr><td><strong>ARRIVAL</strong></td><td>Hyperbolic capture into a closed orbit</td></tr></tbody></table><p>Each phase title is a deep link into the matching <code>/science</code> chapter. The lens also unlocks a <strong>Conic-section side panel</strong> in the bottom-right that classifies the current arc shape (circle / ellipse / parabola / hyperbola) live from specific orbital energy.</p><hr><h2 id="mission-catalog-·-missions" tabindex="-1">Mission Catalog · <code>/missions</code> <a class="header-anchor" href="#mission-catalog-·-missions" aria-label="Permalink to &quot;Mission Catalog · `/missions`&quot;">​</a></h2><p>All 36 missions in the dataset. 16 Mars + 16 Moon + 4 outer-system entries (Galileo, Voyager 2, New Horizons, Dawn), spanning Mariner 4 (1964) through Starship Mars Crew (concept). The page was previously called &quot;Mission Library&quot;; it was renamed to <strong>Mission Catalog</strong> under <a href="./adr/ADR-051">ADR-051</a> to free the word <em>Library</em> for the outbound-link inventory at <code>/library</code>.</p><p><a href="screenshots/04-missions.png"><img src="'+p+'" alt="Catalog"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong><code>FILTERS ▸</code> toggle</strong> at the top — expands the timeline navigator + filter pills (collapsed by default for a clean grid). When you land via a deep link with filter params (<code>?dest=MARS</code>, <code>?from=1969</code>, etc.) the strip auto-expands so you can see what&#39;s active.</li><li><strong>Filter</strong> by destination / agency / status.</li><li><strong>Timeline navigator</strong> — scrub the year window (1957 → 2035) to narrow the set.</li><li><strong>Click any card</strong> — opens a detail panel with OVERVIEW · FLIGHT · GALLERY · LEARN · SCIENCE tabs.</li><li><strong>▶ FLY</strong> from any panel — jumps to <code>/fly?mission=&lt;id&gt;</code>.</li><li><strong>FLIGHT tab</strong> carries per-mission ∆v ledgers, with caveat banners (RECONSTRUCTED / SPARSE / UNKNOWN) when the public data is incomplete.</li></ul><p><a href="screenshots/mission-panel.png"><img src="'+u+'" alt="Mission detail"></a></p><hr><h2 id="earth-orbit-·-earth" tabindex="-1">Earth Orbit · <code>/earth</code> <a class="header-anchor" href="#earth-orbit-·-earth" aria-label="Permalink to &quot;Earth Orbit · `/earth`&quot;">​</a></h2><p>Logarithmic radial scale showing the infrastructure that surrounds Earth: ISS, Tiangong, Hubble, JWST, Gaia, Chandra, XMM-Newton, LRO + the four GNSS constellations (GPS, Galileo, GLONASS, BeiDou) + GEO ring.</p><p><a href="screenshots/05-earth.png"><img src="'+m+'" alt="Earth orbit"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>3D toggle</strong> — drag to orbit Earth; objects sit at their real inclinations.</li><li><strong>2D toggle</strong> — top-down view with logarithmic radial spacing. ISS sits at one ring, GEO at another, JWST near the L2 marker.</li><li><strong>Click any object</strong> — detail panel with launch / period / inclination / crew / capability fields, plus GALLERY · LEARN · SCIENCE tabs.</li><li><strong>Layer chips</strong> (top-left) toggle visibility for stations · observatories · constellations · comsats · Moon-orbiters · orbits.</li></ul><p><strong>Lens layers</strong>: an <strong>atmosphere shell</strong> at the Kármán line (100 km) and <strong>ozone-hole indicators</strong> over both poles (Antarctic + Arctic depletion zones) appear when the Science Lens is on.</p><hr><h2 id="moon-map-·-moon" tabindex="-1">Moon Map · <code>/moon</code> <a class="header-anchor" href="#moon-map-·-moon" aria-label="Permalink to &quot;Moon Map · `/moon`&quot;">​</a></h2><p>16 lunar landing sites across 5 nations, plotted by latitude / longitude on a 3D Moon globe and a 2D equirectangular projection.</p><p><a href="screenshots/06-moon.png"><img src="'+y+'" alt="Moon map"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>3D Moon</strong> — drag to rotate, click any marker for site detail.</li><li><strong>2D map</strong> — equirectangular projection; click any marker for the same panel.</li><li><strong>Site panel</strong> — OVERVIEW · GALLERY · LEARN · SCIENCE, plus mission-specific fields (crew, surface time, samples returned, capability unlocked).</li></ul><p><strong>Lens layer</strong>: <strong>tidal-lock indicator</strong> marks the Moon&#39;s near-side hemisphere (always Earth-facing — the result of synchronous rotation) when the Science Lens is on.</p><hr><h2 id="mars-surface-map-·-mars" tabindex="-1">Mars Surface Map · <code>/mars</code> <a class="header-anchor" href="#mars-surface-map-·-mars" aria-label="Permalink to &quot;Mars Surface Map · `/mars`&quot;">​</a></h2><p>Equirectangular 2D map + 3D globe with surface-feature panels for landing sites, orbital probes, and major regions.</p><p><a href="screenshots/07-mars.png"><img src="'+f+'" alt="Mars map"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>3D / 2D toggle</strong> — drag the globe in 3D or scrub a flat equirectangular projection.</li><li><strong>16 surface sites</strong> (rovers, landers, sample-return) + <strong>11 orbital probes</strong>, each clickable for a detail panel.</li><li><strong>Rover traverse paths</strong> overlaid as cross-linked routes on Curiosity, Perseverance, Opportunity, Spirit.</li><li><strong>Layer chips</strong> — toggle surface vs orbital separately.</li><li><strong>Lens layer</strong>: an <strong>atmosphere shell</strong> at ~120 km marks Mars&#39;s effective atmospheric edge.</li><li><strong>Cross-links</strong>: Curiosity / Perseverance panels deep-link to <code>/missions/&lt;id&gt;</code> for the full mission record.</li></ul><hr><h2 id="iss-explorer-·-iss" tabindex="-1">ISS Explorer · <code>/iss</code> <a class="header-anchor" href="#iss-explorer-·-iss" aria-label="Permalink to &quot;ISS Explorer · `/iss`&quot;">​</a></h2><p>A full station-explorer route with raycast-pickable modules. 18 modules from every USOS + ROS module to visiting craft (Crew Dragon, Cargo Dragon, Soyuz MS, Cygnus, Progress MS, HTV-X, Starliner, Shenzhou, Tianzhou).</p><p><a href="screenshots/08-iss.png"><img src="'+b+'" alt="ISS Explorer"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Drag</strong> to orbit the station; <strong>scroll</strong> to zoom; <strong>right-drag</strong> (or two-finger drag on touch) to pan.</li><li><strong>Click any module</strong> — opens a detail panel with <strong>OVERVIEW · GALLERY · TECHNICAL · ANATOMY · SCIENCE · LEARN</strong> tabs.</li><li><strong><code>MODULES</code> button</strong> — opens a drawer listing every module with its agency badge; click any entry to fly the camera to it.</li><li><strong><code>PAUSE SPIN</code> / <code>RESUME SPIN</code></strong> — freeze the station&#39;s rotation for clear screenshots.</li><li><strong><code>RESET</code></strong> — return to the default camera position.</li><li><strong>Solar arrays auto-track the Sun</strong> with a slow continuous rotation.</li><li><strong>Hover any module</strong> to see its name in a label sprite that tracks the module&#39;s projected screen position.</li></ul><p><strong>ANATOMY tab</strong>: hand-drawn schematics for 9 visiting spacecraft (Crew Dragon, Cargo Dragon, Cygnus, Soyuz MS, Progress MS, HTV-X, Starliner, Shenzhou, Tianzhou) — each shows hatch/docking, propulsion, life-support, and trunk layouts with named callouts.</p><p><strong>Orbit-regime banner</strong> at the top reads ALT · INCL · PERIOD with <strong>Why?</strong> popovers on each value (why ~400 km, why 51.6°, why ~92 min, why 16 sunrises a day).</p><p><strong>Lens layer</strong>: turn on the Science Lens for a <strong>microgravity axes overlay</strong> — three colour-keyed body axes (zenith/nadir, prograde/retrograde, port/starboard) drawn at the station centre with value labels at each arrow tip.</p><hr><h2 id="tiangong-explorer-·-tiangong" tabindex="-1">Tiangong Explorer · <code>/tiangong</code> <a class="header-anchor" href="#tiangong-explorer-·-tiangong" aria-label="Permalink to &quot;Tiangong Explorer · `/tiangong`&quot;">​</a></h2><p>China&#39;s space station. Tianhe core + Wentian + Mengtian lab modules with sun-tracking gallium-arsenide arrays. Mirrors the <code>/iss</code> UX on the same shared <code>station-geometry</code> library.</p><p><a href="screenshots/09-tiangong.png"><img src="'+v+'" alt="Tiangong Explorer"></a></p><p><strong>What you can do</strong> (matches <code>/iss</code> interactions):</p><ul><li><strong>Click any module</strong> — detail panel with same tab set as <code>/iss</code>.</li><li><strong><code>MODULES</code> drawer</strong> with agency badges (CMSA · CASC).</li><li><strong>2D blueprint views</strong> — <code>2D ▾</code> switches between top, side, and front orthographic projections.</li><li><strong>Per-module hover labels</strong> + selected-module emissive pulse.</li><li><strong>Microgravity axes overlay</strong> lens-gated, same as <code>/iss</code>.</li></ul><p><strong>Visiting craft</strong> (Shenzhou crewed + Tianzhou cargo) render in their docked positions.</p><hr><h2 id="science-encyclopedia-·-science" tabindex="-1">Science Encyclopedia · <code>/science</code> <a class="header-anchor" href="#science-encyclopedia-·-science" aria-label="Permalink to &quot;Science Encyclopedia · `/science`&quot;">​</a></h2><p>The in-app explainer for every concept the simulator visualises. <strong>54 sections across 8 tabs</strong>, plus an 8-chapter Space-101 editorial narrative on the landing page.</p><p><a href="screenshots/10-science-landing.png"><img src="'+w+'" alt="Science encyclopedia landing"></a></p><p><strong>Tabs</strong>:</p><table tabindex="0"><thead><tr><th>Tab</th><th>What&#39;s in it</th><th>Sections</th></tr></thead><tbody><tr><td><strong>Orbits</strong></td><td>Kepler&#39;s laws, vis-viva, semi-major axis, eccentricity, inclination, true anomaly, apsides, orbit regimes, Keplerian orbit</td><td>9</td></tr><tr><td><strong>Transfers</strong></td><td>Hohmann, Lambert problem, transfer ellipse, free return, gravity assist, conic sections, patched conics</td><td>7</td></tr><tr><td><strong>Propulsion</strong></td><td>Tsiolkovsky equation, specific impulse, ∆v budget, C3 launch energy, V∞, Oberth effect</td><td>6</td></tr><tr><td><strong>Mission Phases</strong></td><td>Launch, trans-X injection, TCM, orbit insertion, EDL, EVA, MET, NRHO, mission types</td><td>9</td></tr><tr><td><strong>Scales &amp; Time</strong></td><td>AU, light-minute, ecliptic plane, J2000, sidereal vs synodic, reference frames, long-duration</td><td>7</td></tr><tr><td><strong>Porkchop</strong></td><td>What is a porkchop, departure axis, time-of-flight axis, ∆v heatmap, contour reading, viability</td><td>6</td></tr><tr><td><strong>Space Stations</strong></td><td>Pressurised volume, node-module structure, solar-power budget, expedition cadence</td><td>4</td></tr><tr><td><strong>History</strong></td><td>Kepler 1609 · Newton 1687 · Tsiolkovsky 1903 · Goddard 1926 · Sputnik 1957 · Apollo 11 1969</td><td>6</td></tr></tbody></table><p><a href="screenshots/10-science-section.png"><img src="'+k+'" alt="Science section page"></a></p><p><strong>What you can do</strong>:</p><ul><li><strong>Click any tab</strong> in the left rail (sticky on desktop; folds to a single column on mobile).</li><li><strong>Right rail</strong> lists every section in the active tab; click to navigate, current section is highlighted.</li><li><strong>Cmd-K / Ctrl-K</strong> opens a search overlay across the entire encyclopedia — type a few letters of any concept (vis-viva, Hohmann, Kármán, etc.) and Enter navigates straight to the section.</li><li><strong>Cross-screen <code>?</code> chips</strong> — every numeric label across <code>/missions</code>, <code>/fly</code>, <code>/explore</code>, <code>/plan</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code> carries a <code>?</code> chip that deep-links to the matching encyclopedia section.</li><li><strong>Why? popovers</strong> on individual values inline-explain the meaning without a route change.</li></ul><p><strong>Math</strong>: KaTeX server-rendered at build time per <a href="./adr/ADR-034">ADR-034</a> — the client receives static HTML, no JavaScript math library is shipped. <strong>Diagrams</strong>: 62 hand-coded SVGs (54 per-section + 8 tab covers; engineering blueprint style — white-on-black with teal accents) per <a href="./adr/ADR-035">ADR-035</a>.</p><hr><h2 id="provenance-pages" tabindex="-1">Provenance pages <a class="header-anchor" href="#provenance-pages" aria-label="Permalink to &quot;Provenance pages&quot;">​</a></h2><h3 id="credits-—-every-image-text-source-and-logo" tabindex="-1"><code>/credits</code> — every image, text source, and logo <a class="header-anchor" href="#credits-—-every-image-text-source-and-logo" aria-label="Permalink to &quot;`/credits` — every image, text source, and logo&quot;">​</a></h3><p>Public attribution page generated from <code>static/data/image-provenance.json</code> (auto-built by <code>scripts/build-image-provenance.ts</code>), <code>static/data/text-sources.json</code>, and <code>static/data/source-logos.json</code>. Every image in the app appears here with its license, source, and the original URL.</p><p><a href="screenshots/14-credits.png"><img src="'+S+'" alt="Credits page"></a></p><p>Image sourcing is <strong>agency-first</strong> per <a href="./adr/ADR-046">ADR-046</a>: NASA / ESA / ISRO / CNSA / JAXA / KARI / Roscosmos before Wikimedia Commons fallback. Per-image provenance is AJV-validated and <strong>fail-closed</strong> in <code>validate-data</code> (per <a href="./adr/ADR-047">ADR-047</a>) — adding an image without a provenance row breaks CI.</p><h3 id="library-—-every-outbound-learn-link" tabindex="-1"><code>/library</code> — every outbound LEARN link <a class="header-anchor" href="#library-—-every-outbound-learn-link" aria-label="Permalink to &quot;`/library` — every outbound LEARN link&quot;">​</a></h3><p>Bill-of-links across the entire app. Each external link the app exposes (in panel LEARN tabs, <code>/science</code> references, <code>/credits</code> source URLs) appears here with its provenance row: source agency, language, freshness check date, status.</p><p><a href="screenshots/15-library.png"><img src="'+E+'" alt="Library page"></a></p><p>Link policy is <strong>agency-first, native-language priority</strong> per <a href="./adr/ADR-051">ADR-051</a>: for non-US entities, the operator&#39;s own page (in their own language) wins over the NASA mirror. Roscosmos before Wikipedia. ISRO before press releases. The link-checker (<code>scripts/check-learn-links.ts</code>) is chained into <code>npm run fetch</code> so dead links are flagged before they ship.</p><hr><h2 id="mobile" tabindex="-1">Mobile <a class="header-anchor" href="#mobile" aria-label="Permalink to &quot;Mobile&quot;">​</a></h2><p>Every screen works at 375 px width. Touch targets are 44×44 px minimum. Bottom-sheet panels swipe down to dismiss. The porkchop magnifier loupe is mobile-only (long-press on the plot).</p><p>The PWA manifest is shipped — install Orrery as a standalone app via the browser menu (Chrome / Safari / Firefox all support this; the in-app install nag is intentionally suppressed per <a href="./adr/ADR-029">ADR-029</a>).</p><hr><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><ul><li>No analytics.</li><li>No tracking.</li><li>No cookies.</li><li>No <code>localStorage</code>.</li><li>No third-party fonts, images, or scripts loaded at runtime — every asset is bundled at build time per <a href="./adr/ADR-016">ADR-016</a>.</li></ul><p>The only state that persists across sessions is what&#39;s in the URL (<code>?lang=</code>, <code>?mission=</code>, <code>?dest=</code>, etc.) and the service-worker cache (so the app works offline after the first load).</p><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>The 3D scene is empty.</strong> Most likely WebGL is disabled in your browser. Try a different browser or enable WebGL.</p><p><strong>The 3D scene drops to a list view.</strong> <code>/iss</code> and <code>/tiangong</code> auto-fall back to a module list when measured FPS drops below 20 (typically on integrated GPUs running with software rasterisation). Reload — sometimes the first paint is slower than later runs.</p><p><strong>Images don&#39;t load.</strong> Either you&#39;re offline before the service worker has cached them, or the agency image API is rate-limiting. Reload after a minute; cached images persist.</p><p><strong>A translation looks weird.</strong> All 14 locales now ship at 100% UI parity AND full editorial overlay coverage as of v0.5.x. If a string reads off, file an issue; the <a href="./i18n-style-guide">i18n style guide</a> is the binding source of truth per <a href="./adr/ADR-033">ADR-033</a>.</p><p><strong>Missions render outside the camera.</strong> For lunar missions the camera is tight on Earth + Moon (Sun off-camera by design — see <a href="./adr/ADR-031">ADR-031</a> Wave 1 scope). Drag to pan; scroll to zoom.</p><p><strong>A linked external page is dead.</strong> File an issue or PR — the provenance manifest at <code>static/data/link-provenance.json</code> is the source of truth and welcomes corrections. Run <code>npm run check-learn-links -- --update</code> to regenerate the freshness gates.</p><hr><h2 id="where-to-next" tabindex="-1">Where to next <a class="header-anchor" href="#where-to-next" aria-label="Permalink to &quot;Where to next&quot;">​</a></h2><ul><li><strong><a href="./concept/02_Project_Concept">02 Project Concept</a></strong> — the complete synthesis of what Orrery is.</li><li><strong><a href="./concept/03_Data_Catalog">03 Data Catalog</a></strong> — every constant, every source, mission schema, credit format.</li><li><strong><a href="./i18n-style-guide">i18n style guide</a></strong> — the binding glossary for translators.</li><li><strong><code>CLAUDE.md</code></strong> in the repo root — engineering constraints if you&#39;re contributing code (visible on GitHub: <a href="https://github.com/chipi/orrery/blob/main/CLAUDE.md" target="_blank" rel="noreferrer">https://github.com/chipi/orrery/blob/main/CLAUDE.md</a>).</li><li><strong>In-app</strong>: open the <code>/science</code> encyclopedia and read the <strong>Space-101</strong> narrative on the landing page — an 8-chapter primer that takes you from &quot;what is an orbit&quot; to &quot;how a Hohmann transfer works&quot; with no jargon.</li></ul>',121)])])}const _=t(x,[["render",A]]);export{P as __pageData,_ as default};
